// TG-142: Fetch competitor Google Places data
const apiKey = 'GOOGLE_PLACES_API_KEY_PLACEHOLDER';
const competitors = [
  { name: 'Ace Lawn Care Madison', placeId: 'COMPETITOR_1_PLACE_ID' },
  { name: 'Greenmaster Lawn Madison', placeId: 'COMPETITOR_2_PLACE_ID' },
  { name: 'Capital Lawn Care Madison', placeId: 'COMPETITOR_3_PLACE_ID' }
];

const results = [];

for (const comp of competitors) {
  try {
    const data = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://places.googleapis.com/v1/places/${comp.placeId}`,
      headers: {
        'X-Goog-Api-Key': apiKey,
        'X-Goog-FieldMask': 'rating,userRatingCount,reviews'
      }
    });
    results.push({
      name: comp.name,
      placeId: comp.placeId,
      rating: data.rating || null,
      reviewCount: data.userRatingCount || 0,
      latestReviews: (data.reviews || []).slice(0, 3).map(r => ({
        author: r.authorAttribution ? r.authorAttribution.displayName : 'Anonymous',
        rating: r.rating || 0,
        text: r.text ? r.text.text : '',
        time: r.publishTime || ''
      })),
      error: null
    });
  } catch (e) {
    results.push({
      name: comp.name,
      placeId: comp.placeId,
      rating: null,
      reviewCount: 0,
      latestReviews: [],
      error: e.message || 'Failed to fetch'
    });
  }
}

return [{ json: { competitors: results } }];

// TG-142: Fetch TotalGuard Google Places data
const apiKey = 'GOOGLE_PLACES_API_KEY_PLACEHOLDER';
const placeId = 'ChIJMQEDNR3apwMRFbkOyDYmDAE';

const competitors = $input.first().json.competitors;

let tg = { name: 'TotalGuard', rating: null, reviewCount: 0, error: null };
try {
  const data = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://places.googleapis.com/v1/places/${placeId}`,
    headers: {
      'X-Goog-Api-Key': apiKey,
      'X-Goog-FieldMask': 'rating,userRatingCount,reviews'
    }
  });
  tg.rating = data.rating || null;
  tg.reviewCount = data.userRatingCount || 0;
} catch (e) {
  tg.error = e.message || 'Failed to fetch';
}

return [{ json: { totalguard: tg, competitors } }];

// TG-142: Compare & Score competitors vs TotalGuard
const { totalguard, competitors } = $input.first().json;

const supabaseUrl = 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = 'sb_publishable_DeX21ldoDKl3NyJeFZzR1w_eWBUkx-v';
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`,
  'Content-Type': 'application/json'
};

const today = new Date().toISOString().split('T')[0];
const oneWeekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

const alerts = [];
const scored = [];

for (const comp of competitors) {
  // Fetch last week's snapshot for delta calculation
  let lastSnapshot = null;
  try {
    const snapshots = await this.helpers.httpRequest({
      method: 'GET',
      url: `${supabaseUrl}/competitor_snapshots?competitor_name=eq.${encodeURIComponent(comp.name)}&snapshot_date=gte.${oneWeekAgo}&order=snapshot_date.desc&limit=1`,
      headers: supabaseHeaders
    });
    if (Array.isArray(snapshots) && snapshots.length > 0) {
      lastSnapshot = snapshots[0];
    }
  } catch (e) { /* no previous data */ }

  const reviewDelta = lastSnapshot ? comp.reviewCount - (lastSnapshot.review_count || 0) : 0;
  const ratingDelta = lastSnapshot ? (comp.rating || 0) - (lastSnapshot.rating || 0) : 0;

  if (reviewDelta >= 5) {
    alerts.push(`ALERT: ${comp.name} gained ${reviewDelta} reviews this week!`);
  }

  scored.push({
    name: comp.name,
    rating: comp.rating,
    reviewCount: comp.reviewCount,
    reviewDelta,
    ratingDelta: Math.round(ratingDelta * 100) / 100,
    error: comp.error
  });
}

return [{ json: { totalguard, competitors: scored, alerts, snapshot_date: today } }];

// TG-142: Store competitor snapshots in Supabase
const { competitors, snapshot_date, totalguard } = $input.first().json;

const supabaseUrl = 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = 'sb_publishable_DeX21ldoDKl3NyJeFZzR1w_eWBUkx-v';
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

// Store each competitor snapshot
for (const comp of competitors) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${supabaseUrl}/competitor_snapshots`,
      headers: supabaseHeaders,
      body: {
        competitor_name: comp.name,
        rating: comp.rating,
        review_count: comp.reviewCount,
        snapshot_date
      }
    });
  } catch (e) { /* continue on fail */ }
}

// Also store TotalGuard's own snapshot for trend tracking
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${supabaseUrl}/competitor_snapshots`,
    headers: supabaseHeaders,
    body: {
      competitor_name: 'TotalGuard',
      rating: totalguard.rating,
      review_count: totalguard.reviewCount,
      snapshot_date
    }
  });
} catch (e) { /* continue on fail */ }

return $input.all();

