={{ (function() {
  const d = $json;
  const tg = d.totalguard;
  const lines = [
    'COMPETITOR INTELLIGENCE',
    `Week of ${d.snapshot_date}`,
    '',
    `TotalGuard: ${tg.rating || 'N/A'} \u2b50 (${tg.reviewCount} reviews)`,
    ''
  ];
  for (const c of d.competitors) {
    const delta = c.reviewDelta > 0 ? ` (+${c.reviewDelta})` : c.reviewDelta < 0 ? ` (${c.reviewDelta})` : '';
    const rDelta = c.ratingDelta !== 0 ? ` [rating ${c.ratingDelta > 0 ? '+' : ''}${c.ratingDelta}]` : '';
    lines.push(`${c.name}: ${c.rating || 'N/A'} \u2b50 (${c.reviewCount} reviews${delta})${rDelta}`);
  }
  if (d.alerts.length > 0) {
    lines.push('');
    lines.push('\u26a0\ufe0f ALERTS:');
    for (const a of d.alerts) lines.push(a);
  }
  return lines.join('\n');
})() }}
